//dataImage.js
import { $Browser } from '../core/browser-detect';
import { btoa } from '../core/zcglobal';

export function getSVGImage(patternEle, base64) {
    var xml =
        `<svg xmlns='http://www.w3.org/2000/svg' xmlns:xlink='http://www.w3.org/1999/xlink' width='${patternEle.w}' height='${
            patternEle.h
        }'>${new XMLSerializer().serializeToString(patternEle.node.node())}<path d='` +
        `M-5,-5 L5,-5 L5,5 L-5,5 Z` +
        `' transform='translate(${patternEle.w / 2},${patternEle.h / 2})' style='fill: ` +
        `url(#${patternEle.id})'></path> </svg>`;
    return {
        url: $Browser.FIREFOX || base64 ? `data:image/svg+xml;base64,${btoa(xml)}` : `data:image/svg+xml;utf8,${xml}`,
        width: patternEle.w,
        height: patternEle.h
    };
}
